import { registerLayout, getLayout, setDefaultLayout, resolveLayout } from 'metaowl'

registerLayout('admin', AdminLayout)
setDefaultLayout('admin')
const Layout = getLayout('admin')

// In page component
static layout = 'admin'   // or false to disable

import { Cache } from 'metaowl'

await Cache.set('key', { foo: 'bar' })
const value = await Cache.get('key')
await Cache.remove('key')
await Cache.clear()
const keys = await Cache.keys()

import { configureOwl } from 'metaowl'

// Call before boot()
configureOwl({
  warnIfNoStaticProps: true,
  willStartTimeout: 10000,
  translatableAttributes: ['title', 'placeholder', 'label', 'alt'],
})

import { buildRoutes } from 'metaowl'

// Converts import.meta.glob result into a route table
const routes = buildRoutes(import.meta.glob('./pages/**/*.js', { eager: true }))

import { beforeEach, afterEach } from 'metaowl'

beforeEach((to, from, next) => {
  if (to.meta.requiresAuth && !isLoggedIn) {
    next('/login')
  } else {
    next()
  }
})

afterEach((to, from) => {
  console.log('Navigated to', to.path)
})

import { ErrorBoundary } from 'metaowl'

const app = ErrorBoundary.wrap(AppComponent)
app.mount(document.body)

ErrorBoundary.onError((error, context) => {
  console.error(error, context)
})

